//! Compiled topology representation shared with `gnosis-uring`.
//!
//! A topology is a directed acyclic graph where:
//!   - Nodes are operations (accept, parse, resolve, compress, send)
//!   - Edges are scheduling primitives (FORK, RACE, FOLD, VENT)
//!
//! Betty compiles .gg source into this representation at build time.
//! The chaos swarm walks the same static DAG as the transport executor.
//!
//! For the static file server topology:
//!
//! ```text
//! (accept)-[:FORK]->(conn)
//! (conn)-[:PROCESS]->(parsed)
//! (parsed)-[:FORK]->(cache, mmap, disk)
//! (cache | mmap | disk)-[:RACE]->(resolved)
//! (resolved)-[:PROCESS]->(headers)
//! (headers)-[:PROCESS]->(sendfile)
//! ```

/// Edge type — the four primitives plus delayed projection.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Edge {
    /// Fan-out: submit N operations in parallel.
    Fork,

    /// First-to-complete wins, cancel losers.
    Race,

    /// Gather all completions, combine.
    Fold,

    /// Controlled failure / cancellation.
    Vent,

    /// Deferred projection: fork without folding.
    /// The computation stays in trit space. No collapse.
    /// Lean: DelayedProjectionRuntime.addDelayedOp
    Delay,

    /// Sequential computation (no io_uring, just CPU).
    Process,
}

/// Node type — what the operation does.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum NodeOp {
    /// Accept incoming TCP connections.
    Accept,

    /// Parse HTTP request from raw bytes.
    ParseHttp,

    /// Look up file in memory cache.
    CacheLookup,

    /// Memory-map a file.
    MmapRead,

    /// Read file via io_uring.
    DiskRead,

    /// Compress with a specific codec.
    Compress(Codec),

    /// Build HTTP response headers.
    BuildHeaders,

    /// Send a memory-backed response via io_uring writev.
    Send,

    /// Send a file-backed response via io_uring writev + splice/sendfile.
    Sendfile,
}

/// Compression codec.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Codec {
    Identity,
    Gzip,
    Brotli,
    Deflate,
}

/// A node in the topology DAG.
#[derive(Debug)]
pub struct Node {
    pub id: u16,
    pub op: NodeOp,
}

/// A directed edge in the topology DAG.
#[derive(Debug)]
pub struct TopoEdge {
    pub from: u16,
    pub to: &'static [u16],
    pub edge_type: Edge,
}

/// Compiled topology — a static DAG.
pub struct Topology {
    pub nodes: &'static [Node],
    pub edges: &'static [TopoEdge],
}

// ═══════════════════════════════════════════════════════════════════
// Static file server topology (the one that competes on TechEmpower)
// ═══════════════════════════════════════════════════════════════════

/// The static file server topology with zero-copy identity sends.
pub static STATIC_SERVER: Topology = Topology {
    nodes: &[
        Node {
            id: 0,
            op: NodeOp::Accept,
        },
        Node {
            id: 1,
            op: NodeOp::ParseHttp,
        },
        Node {
            id: 2,
            op: NodeOp::CacheLookup,
        },
        Node {
            id: 3,
            op: NodeOp::MmapRead,
        },
        Node {
            id: 4,
            op: NodeOp::DiskRead,
        },
        Node {
            id: 5,
            op: NodeOp::BuildHeaders,
        },
        Node {
            id: 6,
            op: NodeOp::Sendfile,
        },
    ],
    edges: &[
        TopoEdge {
            from: 0,
            to: &[1],
            edge_type: Edge::Fork,
        },
        TopoEdge {
            from: 1,
            to: &[2, 3, 4],
            edge_type: Edge::Fork,
        },
        TopoEdge {
            from: 2,
            to: &[5],
            edge_type: Edge::Race,
        },
        TopoEdge {
            from: 3,
            to: &[5],
            edge_type: Edge::Race,
        },
        TopoEdge {
            from: 4,
            to: &[5],
            edge_type: Edge::Race,
        },
        TopoEdge {
            from: 5,
            to: &[6],
            edge_type: Edge::Process,
        },
    ],
};
